body.script:
//

  /* ── UNKNOWN URL REDIRECT — unrecognised pages go to home ── */
  (function() {
    var known = ['/', '/p/casestudy.html', '/p/about.html', '/p/playground.html', '/p/friender-case-study.html', '/p/case-study-2.html'];
    var path  = window.location.pathname.toLowerCase();
    var isKnown = known.some(function(k) {
      return path === k || path === k.replace('.html', '');
    });
    if (!isKnown) { window.location.replace('/'); }
  })();

  /* ── PAGE ROUTER: show correct div by URL — runs before paint ── */
  (function() {
    var path = window.location.pathname.toLowerCase();
    var id = null;
    if      (path.indexOf('friender')    !== -1) id = 'pm-friender';
    else if (path.indexOf('case-study-2') !== -1 || path.indexOf('casestudy2') !== -1 || path === '/p/case-study-2.html') id = 'pm-cs2';
    else if (path.indexOf('casestudy')  !== -1) id = 'pm-cs';
    else if (path.indexOf('playground') !== -1) id = 'pm-play';
    else if (path.indexOf('about')      !== -1) id = 'pm-about';
    if (id) {
      var el = document.getElementById(id);
      if (el) {
        el.style.display = '';
        el.style.visibility = 'visible';
      }
    }
  })();

  /* ── SKELETON LOADER ── */
  (function() {
    var imgs = document.querySelectorAll('img[loading="lazy"]');
    imgs.forEach(function(img) {
      var wrap = img.closest('.pm-img-wrap');
      if (!wrap) return;
      if (img.complete && img.naturalWidth > 0) { wrap.classList.add('pm-img-loaded'); return; }
      img.addEventListener('load',  function() { wrap.classList.add('pm-img-loaded'); });
      img.addEventListener('error', function() { wrap.classList.add('pm-img-loaded'); });
    });
  })();

  /* ── PAGE ENTRANCE ANIMATION ── */
  /* Finds the visible .pm-inner and stagger-animates its direct children */
  function pmRunEntranceAnimation() {
    /* Small delay so the browser has painted the newly visible content */
    requestAnimationFrame(function() {
      requestAnimationFrame(function() {
        /* Target all visible .pm-inner containers */
        var inners = document.querySelectorAll('.pm-inner');
        inners.forEach(function(inner) {
          /* Skip if inside a hidden page div */
          var pageDiv = inner.closest('[id^="pm-"]');
          if (pageDiv && pageDiv.style.display === 'none') return;

          var children = Array.prototype.slice.call(inner.children);
          children.forEach(function(child, i) {
            /* Reset any previous animation state */
            child.classList.remove('pm-animate-in');
            child.style.animationDelay = '';
            /* Force reflow so removing the class takes effect */
            void child.offsetWidth;
            /* Stagger: 80ms between each section, starting at 60ms */
            child.style.animationDelay = (60 + i * 80) + 'ms';
            child.classList.add('pm-animate-in');
          });
        });
      });
    });
  }

  /* Run on initial page load */
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', pmRunEntranceAnimation);
  } else {
    pmRunEntranceAnimation();
  }

  /* ── LIGHTBOX with prev/next navigation ── */
  (function() {
    var lb      = document.getElementById('pm-lightbox');
    var lbImg   = document.getElementById('pm-lightbox-img');
    var lbClose = document.getElementById('pm-lightbox-close');
    var lbPrev  = document.getElementById('pm-lightbox-prev');
    var lbNext  = document.getElementById('pm-lightbox-next');

    var images  = []; /* collected at open time [{src,alt}] */
    var current = 0;

    function collect() {
      images = [];
      document.querySelectorAll('.pm-pg-image img').forEach(function(el) {
        images.push({ src: el.src, alt: el.alt || '' });
      });
    }

    function show(idx) {
      if (idx < 0 || idx >= images.length) return;
      current   = idx;
      lbImg.src = images[current].src;
      lbImg.alt = images[current].alt;
      if (lbPrev) {
        lbPrev.style.opacity       = current > 0 ? '0.85' : '0.25';
        lbPrev.style.pointerEvents = current > 0 ? 'auto' : 'none';
      }
      if (lbNext) {
        lbNext.style.opacity       = current < images.length - 1 ? '0.85' : '0.25';
        lbNext.style.pointerEvents = current < images.length - 1 ? 'auto' : 'none';
      }
    }

    function open(src) {
      collect();
      var idx = 0;
      for (var i = 0; i < images.length; i++) {
        if (images[i].src === src) { idx = i; break; }
      }
      show(idx);
      lb.classList.add('active');
      document.body.style.overflow = 'hidden';
    }

    function close() {
      lb.classList.remove('active');
      document.body.style.overflow = '';
      lbImg.src = '';
    }

    /* Click image to open */
    document.addEventListener('click', function(e) {
      var img = e.target.closest('.pm-pg-image img');
      if (!img) return;
      var isMobile = ('ontouchstart' in window) || window.matchMedia('(max-width: 480px)').matches;
      if (isMobile) { window.open(img.src, '_blank'); }
      else { open(img.src); }
    });

    /* Prev */
    if (lbPrev) lbPrev.addEventListener('click', function(e) {
      e.stopPropagation(); show(current - 1);
    });

    /* Next */
    if (lbNext) lbNext.addEventListener('click', function(e) {
      e.stopPropagation(); show(current + 1);
    });

    /* Close button */
    if (lbClose) lbClose.addEventListener('click', close);

    /* Backdrop click */
    lb.addEventListener('click', function(e) { if (e.target === lb) close(); });

    /* Keyboard */
    document.addEventListener('keydown', function(e) {
      if (!lb.classList.contains('active')) return;
      if (e.key === 'Escape')     close();
      if (e.key === 'ArrowLeft')  show(current - 1);
      if (e.key === 'ArrowRight') show(current + 1);
    });
  })();

  /* ── SMOOTH SCROLL (desktop only) ── */
  (function() {
    var st = 0, sc = 0, ease = 0.08, raf = null, running = false;
    function lerp(a,b,t){return a+(b-a)*t;}
    function tick(){
      sc=lerp(sc,st,ease);
      if(Math.abs(st-sc)<0.5){sc=st;window.scrollTo(0,sc);running=false;raf=null;return;}
      window.scrollTo(0,sc);raf=requestAnimationFrame(tick);
    }
    if(!('ontouchstart' in window)&&window.matchMedia('(min-width:481px)').matches){
      window.addEventListener('wheel',function(e){
        e.preventDefault();
        st+=e.deltaY*1.2;
        st=Math.max(0,Math.min(st,document.body.scrollHeight-window.innerHeight));
        if(!running){sc=window.scrollY;running=true;if(raf)cancelAnimationFrame(raf);raf=requestAnimationFrame(tick);}
      },{passive:false});
    }
  })();

  /* ── FLOATING NAV ── */
  (function() {
    var items = document.querySelectorAll('.pm-nav-item');
    var pill  = document.getElementById('pm-pill');
    var W = 56;

    function getIdx(path) {
      path = path.toLowerCase();
      /* friender and case-study-2 are sub-pages of case study — highlight nav item 1 */
      if (path.indexOf('friender')     !== -1) return 1;
      if (path.indexOf('case-study-2') !== -1) return 1;
      if (path.indexOf('casestudy')    !== -1) return 1;
      if (path.indexOf('playground')   !== -1) return 2;
      if (path.indexOf('about')        !== -1) return 3;
      return 0;
    }

    function setActive(idx) {
      items.forEach(function(el,i){ el.classList.toggle('active', i===idx); });
      pill.style.transform = 'translateX('+(idx*W)+'px)';
    }

    /* SPA: fetch page HTML, swap content, nav stays permanent */
    var wrap = document.getElementById('pm-content-wrap');

    function showPage(idx) {
      ['pm-cs','pm-play','pm-about','pm-friender','pm-cs2'].forEach(function(id) {
        var el = document.getElementById(id);
        if (el) el.style.display = 'none';
      });
      var ids = [null,'pm-cs','pm-play','pm-about','pm-friender','pm-cs2'];
      if (idx > 0 && ids[idx]) {
        var el = document.getElementById(ids[idx]);
        if (el) el.style.display = '';
      }
    }

    /* Separate content routing from nav routing */
    function getContentId(path) {
      path = path.toLowerCase();
      if (path.indexOf('friender')     !== -1) return 'pm-friender';
      if (path.indexOf('case-study-2') !== -1) return 'pm-cs2';
      if (path.indexOf('casestudy')    !== -1) return 'pm-cs';
      if (path.indexOf('playground')   !== -1) return 'pm-play';
      if (path.indexOf('about')        !== -1) return 'pm-about';
      return null;
    }

    var titleMap = {
      '/': 'Bishal Mistri — Product Designer',
      '/p/casestudy.html': 'Case Study — Bishal Mistri',
      '/p/about.html': 'About — Bishal Mistri',
      '/p/playground.html': 'Playground — Bishal Mistri',
      '/p/friender-case-study.html': 'Friender Case Study — Bishal Mistri',
      '/p/case-study-2.html': 'RBG Case Study — Bishal Mistri'
    };

    var allPageIds = ['pm-cs','pm-play','pm-about','pm-friender','pm-cs2'];

    /* Show/hide existing DOM divs — no fetch needed when content is already in the DOM */
    function showContentById(contentId) {
      allPageIds.forEach(function(id) {
        var el = document.getElementById(id);
        if (el) el.style.display = 'none';
      });
      if (contentId) {
        var el = document.getElementById(contentId);
        if (el) el.style.display = '';
      }
    }

    function navigateSPA(href, idx) {
      setActive(idx);
      var contentId = getContentId(href);
      var normHref  = href.toLowerCase().replace(/^https?:\/\/[^/]+/, '');

      /* ── CASE 1: navigating to HOME (/) ──
         Home uses a different HTML structure (b:if index block), so if
         pm-content-wrap doesn't contain a .pm-hero we must do a hard nav */
      if (!contentId) {
        /* Going to home — if we're already on a static page, the home
           hero content is NOT in the DOM, so do a real navigation */
        if (!document.querySelector('.pm-hero')) {
          window.location.href = href;
          return;
        }
        /* Already on home (hero exists), just update state */
        allPageIds.forEach(function(id) {
          var el = document.getElementById(id);
          if (el) el.style.display = 'none';
        });
        document.title = titleMap[normHref] || 'Bishal Mistri — Product Designer';
        history.pushState({ idx: idx, href: href }, document.title, href);
        window.scrollTo(0, 0);
        pmRunEntranceAnimation();
        return;
      }

      /* ── CASE 2: target content div already exists in the DOM ──
         This covers all nav clicks while on any static page */
      var targetEl = document.getElementById(contentId);
      if (targetEl) {
        if (wrap) { wrap.style.transition = 'opacity 0.18s ease'; wrap.style.opacity = '0'; }
        showContentById(contentId);
        document.title = titleMap[normHref] || 'Bishal Mistri — Product Designer';
        history.pushState({ idx: idx, href: href }, document.title, href);
        window.scrollTo(0, 0);
        requestAnimationFrame(function() {
          if (wrap) wrap.style.opacity = '1';
          pmRunEntranceAnimation();
        });
        return;
      }

      /* ── CASE 3: content not in DOM (navigating from home to a static page) ──
         Fetch the static page and swap content */
      if (wrap) { wrap.style.transition = 'opacity 0.18s ease'; wrap.style.opacity = '0'; }
      fetch(href, { credentials: 'same-origin' })
        .then(function(r) { return r.text(); })
        .then(function(html) {
          var doc = new DOMParser().parseFromString(html, 'text/html');
          var nw  = doc.getElementById('pm-content-wrap');
          if (wrap && nw) { wrap.innerHTML = nw.innerHTML; }
          showContentById(contentId);
          document.title = titleMap[normHref] || 'Bishal Mistri — Product Designer';
          history.pushState({ idx: idx, href: href }, document.title, href);
          window.scrollTo(0, 0);
          if (wrap) requestAnimationFrame(function() { wrap.style.opacity = '1'; });
          pmRunEntranceAnimation();
        })
        .catch(function() { window.location.href = href; });
    }

    items.forEach(function(el) {
      el.addEventListener('click', function() {
        var idx  = parseInt(el.getAttribute('data-index'));
        var href = el.getAttribute('data-href');
        if (!href) return;
        /* Allow navigation even if nav idx matches — user may be on a sub-page
           e.g. on /p/friender-case-study.html clicking case study goes to /p/casestudy.html */
        var currentPath = window.location.pathname.toLowerCase();
        if (idx === getIdx(currentPath) && currentPath === href.toLowerCase()) return;
        navigateSPA(href, idx);
      });
    });

    window.addEventListener('popstate', function(e) {
      if (e.state) {
        navigateSPA(e.state.href, e.state.idx);
      } else { navigateSPA('/', 0); }
    });

    function initNav() {
      var idx = getIdx(window.location.pathname);
      pill.style.transition = 'none';
      setActive(idx);
      requestAnimationFrame(function(){
        requestAnimationFrame(function(){ pill.style.transition = ''; });
      });
    }
    initNav();

  })();

  //
